pub async fn payments_update(
    state: web::Data<app::AppState>,
    req: actix_web::HttpRequest,
    json_payload: web::Json<payment_types::PaymentsRequest>,
    path: web::Path<common_utils::id_type::PaymentId>,
) -> impl Responder {
    let flow = Flow::PaymentsUpdate;
    let mut payload = json_payload.into_inner();
    if let Err(err) = payload
        .validate()
        .map_err(|message| errors::ApiErrorResponse::InvalidRequestData { message })
    {
        return api::log_and_return_error_response(err.into());
    };

    if let Some(api_enums::CaptureMethod::Scheduled) = payload.capture_method {
        return http_not_implemented();
    };

    let payment_id = path.into_inner();

    tracing::Span::current().record("payment_id", payment_id.get_string_repr());

    payload.payment_id = Some(payment_types::PaymentIdType::PaymentIntentId(payment_id));
    let api_auth = auth::ApiKeyAuth {
        allow_connected_scope_operation: true,
        allow_platform_self_operation: false,
    };
    let (auth_type, auth_flow) = match auth::check_internal_api_key_auth_no_client_secret(
        req.headers(),
        api_auth,
        state.conf.internal_merchant_id_profile_id_auth.clone(),
    ) {
        Ok(auth) => auth,
        Err(err) => return api::log_and_return_error_response(report!(err)),
    };

    let locking_action = payload.get_locking_input(flow.clone());

    Box::pin(api::server_wrap(
        flow,
        state,
        &req,
        payload,
        |state, auth: auth::AuthenticationData, mut req, req_state| {
            if let Some(client_secret) = auth.client_secret {
                req.client_secret = Some(client_secret);
            }

            authorize_verify_select::<_>(
                payments::PaymentUpdate,
                state,
                req_state,
                auth.platform,
                auth.profile.map(|profile| profile.get_id().clone()),
                HeaderPayload::default(),
                req,
                auth_flow,
            )
        },
        &*auth_type,
        locking_action,
    ))
    .await
}

pub async fn payments_operation_core<'a, F, Req, Op, FData, D>(
    state: &SessionState,
    req_state: ReqState,
    platform: &domain::Platform,
    profile_id_from_auth_layer: Option<id_type::ProfileId>,
    operation: Op,
    req: Req,
    call_connector_action: CallConnectorAction,
    shadow_ucs_call_connector_action: Option<CallConnectorAction>,
    auth_flow: services::AuthFlow,
    eligible_connectors: Option<Vec<enums::RoutableConnectors>>,
    header_payload: HeaderPayload,
    dimensions: DimensionsWithMerchantId,
) -> RouterResult<(D, Req, Option<u16>, Option<u128>)>
where
    F: Send + Clone + Sync + Debug + 'static,
    Req: Authenticate + Clone,
    Op: Operation<F, Req, Data = D> + Send + Sync,
    D: OperationSessionGetters<F> + OperationSessionSetters<F> + Send + Sync + Clone,

    // To create connector flow specific interface data
    D: ConstructFlowSpecificData<F, FData, router_types::PaymentsResponseData>,
    RouterData<F, FData, router_types::PaymentsResponseData>: Feature<F, FData>,

    // To construct connector flow specific api
    dyn api::Connector:
        services::api::ConnectorIntegration<F, FData, router_types::PaymentsResponseData>,

    // To perform router related operation for PaymentResponse
    PaymentResponse: Operation<F, FData, Data = D>,
    FData: Send + Sync + Clone + router_types::Capturable + 'static + serde::Serialize,
{
    let operation: BoxedOperation<'_, F, Req, D> = Box::new(operation);

    tracing::Span::current().record(
        "merchant_id",
        platform
            .get_processor()
            .get_account()
            .get_id()
            .get_string_repr(),
    );
    let (operation, validate_result) = operation
        .to_validate_request()?
        .validate_request(&req, platform.get_processor())?;

    // Create feature_config
    let feature_config = core_utils::get_feature_config(state, platform).await;

    let payment_method_info = operation
        .to_domain()?
        .fetch_payment_method(state, &req, platform, &feature_config)
        .await?;

    tracing::Span::current().record("payment_id", format!("{}", validate_result.payment_id));

    // get profile from headers
    let operations::GetTrackerResponse {
        operation,
        customer_details,
        mut payment_data,
        business_profile,
        mandate_type,
    } = operation
        .to_get_tracker()?
        .get_trackers(
            state,
            &validate_result.payment_id,
            &req,
            platform,
            auth_flow,
            &header_payload,
            payment_method_info,
        )
        .await?;
    let dimensions = dimensions.with_profile_id(business_profile.get_id().clone());

    operation
        .to_get_tracker()?
        .validate_request_with_state(state, &req, &mut payment_data, &business_profile)
        .await?;

    core_utils::validate_profile_id_from_auth_layer(
        profile_id_from_auth_layer,
        &payment_data.get_payment_intent().clone(),
    )?;

    operation
        .to_domain()?
        .create_payment_method(
            state,
            &req,
            platform,
            &mut payment_data,
            &business_profile,
            &feature_config,
        )
        .await?;

    let (operation, customer) = operation
        .to_domain()?
        // get_customer_details
        .get_or_create_customer_details(
            state,
            &mut payment_data,
            customer_details, // TODO: Remove this field after implicit customer update is removed
            platform.get_provider(),
            platform.get_initiator(),
            dimensions,
        )
        .await
        .to_not_found_response(errors::ApiErrorResponse::CustomerNotFound)
        .attach_printable("Failed while fetching/creating customer")?;

    let connector_customer_map = customer
        .as_ref()
        .and_then(|customer| customer.connector_customer.as_ref());

    let authentication_type = call_decision_manager(
        state,
        platform.get_processor(),
        &business_profile,
        &payment_data,
    )
    .await?;

    payment_data.set_authentication_type_in_attempt(authentication_type);

    operation
        .to_domain()?
        .apply_three_ds_authentication_strategy(state, &mut payment_data, &business_profile)
        .await;

    let connector = choose_connector(
        &operation,
        state,
        &req,
        platform.get_processor(),
        &business_profile,
        &feature_config,
        &mut payment_data,
        eligible_connectors,
        mandate_type,
    )
    .await?;

    let payment_method_token = get_decrypted_wallet_payment_method_token(
        &operation,
        state,
        platform,
        &mut payment_data,
        connector.as_ref(),
    )
    .await?;

    payment_method_token.map(|token| payment_data.set_payment_method_token(Some(token)));

    let (connector, debit_routing_output) = debit_routing::perform_debit_routing(
        &operation,
        state,
        &business_profile,
        &mut payment_data,
        connector,
    )
    .await;

    let should_add_task_to_process_tracker = should_add_task_to_process_tracker(&payment_data);

    let locale = header_payload.locale.clone();

    payment_data = tokenize_in_router_when_confirm_false_or_external_authentication(
        state,
        &operation,
        &mut payment_data,
        &validate_result,
        platform,
        &business_profile,
        &feature_config,
    )
    .await?;

    let mut connector_http_status_code = None;
    let mut external_latency = None;
    if let Some(connector_details) = connector {
        // Fetch and check FRM configs
        #[cfg(feature = "frm")]
        let mut frm_info = None;
        #[allow(unused_variables, unused_mut)]
        let mut should_continue_transaction: bool = true;
        #[cfg(feature = "frm")]
        let mut should_continue_capture: bool = true;
        #[cfg(feature = "frm")]
        let frm_configs = if state.conf.frm.enabled {
            match Box::pin(frm_core::call_frm_before_connector_call(
                &operation,
                platform,
                &mut payment_data,
                state,
                &mut frm_info,
                &mut should_continue_transaction,
                &mut should_continue_capture,
            ))
            .await
            {
                Ok(configs) => configs,
                Err(e) => {
                    // Log the error
                    logger::info!(
                        "FRM call before connector failed : payment_id={:?}, error={:?}",
                        payment_data.get_payment_intent().payment_id,
                        e
                    );
                    metrics::FRM_FAILURE.add(
                        1,
                        router_env::metric_attributes!(
                            (
                                "merchant_id",
                                platform.get_processor().get_account().get_id().clone()
                            ),
                            ("error_type", e.current_context().to_string())

async fn get_trackers<'a>(
    &'a self,
    state: &'a SessionState,
    payment_id: &api::PaymentIdType,
    request: &api::PaymentsRequest,
    platform: &domain::Platform,
    auth_flow: services::AuthFlow,
    _header_payload: &hyperswitch_domain_models::payments::HeaderPayload,
    _payment_method_wrapper: Option<operations::PaymentMethodWithRawData>,
) -> RouterResult<operations::GetTrackerResponse<'a, F, api::PaymentsRequest, PaymentData<F>>>
{
    let (mut payment_intent, mut payment_attempt, currency): (_, _, storage_enums::Currency);

    let payment_id = payment_id
        .get_payment_intent_id()
        .change_context(errors::ApiErrorResponse::PaymentNotFound)?;
    let processor_merchant_id = platform.get_processor().get_account().get_id();
    let storage_scheme = platform.get_processor().get_account().storage_scheme;

    let db = &*state.store;
    helpers::allow_payment_update_enabled_for_client_auth(
        processor_merchant_id,
        state,
        auth_flow,
    )
    .await?;
    payment_intent = db
        .find_payment_intent_by_payment_id_processor_merchant_id(
            &payment_id,
            processor_merchant_id,
            platform.get_processor().get_key_store(),
            storage_scheme,
        )
        .await
        .to_not_found_response(errors::ApiErrorResponse::PaymentNotFound)?;

    // TODO (#7195): Add platform merchant account validation once publishable key auth is solved

    if let Some(order_details) = &request.order_details {
        helpers::validate_order_details_amount(
            order_details.to_owned(),
            payment_intent.amount,
            false,
        )?;
    }

    payment_intent.setup_future_usage = request
        .setup_future_usage
        .or(payment_intent.setup_future_usage);

    helpers::validate_customer_access(&payment_intent, auth_flow, request)?;

    helpers::validate_card_data(
        request
            .payment_method_data
            .as_ref()
            .and_then(|pmd| pmd.payment_method_data.clone()),
    )?;

    helpers::validate_payment_status_against_allowed_statuses(
        payment_intent.status,
        &[
            storage_enums::IntentStatus::RequiresPaymentMethod,
            storage_enums::IntentStatus::RequiresConfirmation,
        ],
        "update",
    )?;
    helpers::authenticate_client_secret(request.client_secret.as_ref(), &payment_intent)?;

    payment_intent.order_details = request
        .get_order_details_as_value()
        .change_context(errors::ApiErrorResponse::InternalServerError)
        .attach_printable("Failed to convert order details to value")?
        .or(payment_intent.order_details);

    payment_attempt = db
        .find_payment_attempt_by_payment_id_processor_merchant_id_attempt_id(
            &payment_intent.payment_id,
            processor_merchant_id,
            payment_intent.active_attempt.get_id().as_str(),
            storage_scheme,
            platform.get_processor().get_key_store(),
        )
        .await
        .to_not_found_response(errors::ApiErrorResponse::PaymentNotFound)?;

    let customer_acceptance = request.customer_acceptance.clone();
    let recurring_details = request.recurring_details.clone();

    let mandate_type = m_helpers::get_mandate_type(
        request.mandate_data.clone(),
        request.off_session,
        payment_intent.setup_future_usage,
        request.customer_acceptance.clone(),
        request.payment_token.clone(),
        payment_attempt.payment_method.or(request.payment_method),
    )
    .change_context(errors::ApiErrorResponse::MandateValidationFailed {
        reason: "Expected one out of recurring_details and mandate_data but got both".into(),
    })?;

    let m_helpers::MandateGenericData {
        token,
        payment_method,
        payment_method_type,
        mandate_data,
        recurring_mandate_payment_data,
        mandate_connector,
        payment_method_info,
    } = Box::pin(helpers::get_token_pm_type_mandate_details(
        state,
        request,
        mandate_type.to_owned(),
        platform,
        None,
        payment_intent.customer_id.as_ref(),
        None,
    ))
    .await?;
    helpers::validate_amount_to_capture_and_capture_method(Some(&payment_attempt), request)?;

    helpers::validate_request_amount_and_amount_to_capture(
        request.amount,
        request.amount_to_capture,
        request
            .surcharge_details
            .or(payment_attempt.get_surcharge_details()),
    )
    .change_context(errors::ApiErrorResponse::InvalidDataFormat {
        field_name: "amount_to_capture".to_string(),
        expected_format: "amount_to_capture lesser than or equal to amount".to_string(),
    })?;

    currency = request
        .currency
        .or(payment_attempt.currency)
        .get_required_value("currency")?;

    payment_attempt.payment_method = payment_method.or(payment_attempt.payment_method);
    payment_attempt.payment_method_type =
        payment_method_type.or(payment_attempt.payment_method_type);
    let customer_details = helpers::get_customer_details_from_request(request);

    payment_intent.customer_details = helpers::merge_request_and_intent_customer_data(
        state,
        payment_intent.customer_details,
        &customer_details,
        platform.get_processor(),
    )
    .await
    .change_context(errors::ApiErrorResponse::InternalServerError)
    .attach_printable("Unable to store customer data in payment intent")?;

    let amount = request
        .amount
        .unwrap_or_else(|| payment_attempt.net_amount.get_order_amount().into());

    if request.confirm.unwrap_or(false) {
        helpers::validate_customer_id_mandatory_cases(
            request.setup_future_usage.is_some(),
            payment_intent
                .customer_id
                .as_ref()
                .or(customer_details.customer_id.as_ref()),
        )?;
    }

    let shipping_address = helpers::create_or_update_address_for_payment_by_request(
        state,
        request.shipping.as_ref(),
        payment_intent.shipping_address_id.as_deref(),
        processor_merchant_id,
        payment_intent
            .customer_id
            .as_ref()
            .or(customer_details.customer_id.as_ref()),
        platform.get_processor().get_key_store(),
        &payment_intent.payment_id,
        platform.get_processor().get_account().storage_scheme,
    )
    .await?;
    let billing_address = helpers::create_or_update_address_for_payment_by_request(
        state,
        request.billing.as_ref(),
        payment_intent.billing_address_id.as_deref(),
        processor_merchant_id,
        payment_intent
            .customer_id
            .as_ref()
            .or(customer_details.customer_id.as_ref()),
        platform.get_processor().get_key_store(),
        &payment_intent.payment_id,
        platform.get_processor().get_account().storage_scheme,
    )
    .await?;

    let payment_method_billing = helpers::create_or_update_address_for_payment_by_request(
        state,
        request
            .payment_method_data
            .as_ref()
            .and_then(|pmd| pmd.billing.as_ref()),
        payment_attempt.payment_method_billing_address_id.as_deref(),
        processor_merchant_id,
        payment_intent
            .customer_id
            .as_ref()
            .or(customer_details.customer_id.as_ref()),
        platform.get_processor().get_key_store(),
        &payment_intent.payment_id,
        platform.get_processor().get_account().storage_scheme,
    )
    .await?;

    payment_intent.shipping_address_id = shipping_address.clone().map(|x| x.address_id);
    payment_intent.billing_address_id = billing_address.clone().map(|x| x.address_id);
    payment_attempt.payment_method_billing_address_id = payment_method_billing
        .as_ref()
        .map(|payment_method_billing| payment_method_billing.address_id.clone());

pub async fn payments_confirm(
    state: web::Data<app::AppState>,
    req: actix_web::HttpRequest,
    json_payload: web::Json<payment_types::PaymentsRequest>,
    path: web::Path<common_utils::id_type::PaymentId>,
) -> impl Responder {
    let flow = Flow::PaymentsConfirm;
    let mut payload = json_payload.into_inner();
    if let Err(err) = payload
        .validate()
        .map_err(|message| errors::ApiErrorResponse::InvalidRequestData { message })
    {
        return api::log_and_return_error_response(err.into());
    };

    if let Some(api_enums::CaptureMethod::Scheduled) = payload.capture_method {
        return http_not_implemented();
    };

    let header_payload = match HeaderPayload::foreign_try_from(req.headers()) {
        Ok(headers) => headers,
        Err(err) => {
            return api::log_and_return_error_response(err);
        }
    };

    if let Err(err) = helpers::populate_browser_info(&req, &mut payload, &header_payload) {
        return api::log_and_return_error_response(err);
    }

    let payment_id = path.into_inner();
    tracing::Span::current().record("payment_id", payment_id.get_string_repr());
    payload.payment_id = Some(payment_types::PaymentIdType::PaymentIntentId(payment_id));
    payload.confirm = Some(true);

    let api_auth = auth::ApiKeyAuth {
        allow_connected_scope_operation: true,
        allow_platform_self_operation: false,
    };

    let (auth_type, auth_flow) = match auth::check_internal_api_key_auth(
        req.headers(),
        &payload,
        api_auth,
        state.conf.internal_merchant_id_profile_id_auth.clone(),
    ) {
        Ok(auth) => auth,
        Err(e) => return api::log_and_return_error_response(e),
    };

    let locking_action = payload.get_locking_input(flow.clone());

    Box::pin(api::server_wrap(
        flow,
        state,
        &req,
        payload,
        |state, auth: auth::AuthenticationData, mut req, req_state| {
            // If client_secret is provided via SDK authorization header, use it
            if let Some(client_secret) = auth.client_secret {
                req.client_secret = Some(client_secret);
            }

            authorize_verify_select::<_>(
                payments::PaymentConfirm,
                state,
                req_state,
                auth.platform,
                auth.profile.map(|profile| profile.get_id().clone()),
                header_payload.clone(),
                req,
                auth_flow,
            )
        },
        &*auth_type,
        locking_action,
    ))
    .await
}

